import React, { useState } from 'react';

// Use the image URL you provided as the background image
const backgroundImage = 'https://i.pinimg.com/originals/3b/0e/47/3b0e471c8ab0445943318ba98ac9b13c.jpg';

const RegistrationPage = () => {
  const [email, setEmail] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = (event) => {
    event.preventDefault();
    // Handle form submission logic here (e.g., API call, state update)
    console.log('Registration details:', { email, username, password });
  };

  return (
    <div
      style={{
        backgroundImage: `url(${backgroundImage})`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        height: '100vh',
        width: '100vw',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
      }}
    >
      <div
        style={{
          backgroundColor: 'rgba(255, 255, 255, 0.8)', // Adjust opacity as desired
          padding: '40px',
          borderRadius: '10px',
          boxShadow: '0px 0px 10px rgba(0, 0, 0, 0.2)',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
        }}
      >
        <h1 style={{ marginBottom: '30px' }}>Register</h1>
        <form onSubmit={handleSubmit}>
          <div style={{ marginBottom: '15px' }}>
            <label htmlFor="email" style={{ fontWeight: 'bold', marginBottom: '5px' }}>
              Email
            </label>
            <input
              type="email"
              id="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              style={{
                width: '300px',
                padding: '10px',
                borderRadius: '5px',
                border: '1px solid #ccc',
              }}
              required
            />
          </div>
          <div style={{ marginBottom: '15px' }}>
            <label htmlFor="username" style={{ fontWeight: 'bold', marginBottom: '5px' }}>
              Username
            </label>
            <input
              type="text"
              id="username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              style={{
                width: '300px',
                padding: '10px',
                borderRadius: '5px',
                border: '1px solid #ccc',
              }}
              required
            />
          </div>
          <div style={{ marginBottom: '25px' }}>
            <label htmlFor="password" style={{ fontWeight: 'bold', marginBottom: '5px' }}>
              Password
            </label>
            <input
              type="password"
              id="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              style={{
                width: '300px',
                padding: '10px',
                borderRadius: '5px',
                border: '1px solid #ccc',
              }}
              required
            />
          </div>
          <button
            type="submit"
            style={{
              backgroundColor: '#007bff', // Adjust based on your color theme
              color: 'white',
              padding: '12px 20px',
              border: 'none',
              borderRadius: '5px',
              cursor: 'pointer',
              fontWeight: 'bold',
            }}
          >
            Register
          </button>
        </form>
      </div>
    </div>
  );
};

export default RegistrationPage;
